function HelloButton() {
  function handleClick() {
    alert('Hello from React!');
  }

  return <button onClick={handleClick()}>Say Hello</button>;
}

function Logger() {
  function report() {
    console.log('clicked!');
  }

  return <button onClick={report}>Go</button>;
}

